---
import BaseLayout from '../layouts/BaseLayout.astro';
const isDev = import.meta.env.DEV;
---
<BaseLayout title="Search - AstroStatic" description="Search all blog posts on AstroStatic using full-text search.">
  <Fragment slot="head">
    <link rel="stylesheet" href="/pagefind/pagefind-ui.css" />
  </Fragment>
  <section class="mx-auto max-w-5xl px-4 py-16">
    <h1 class="text-3xl font-bold mb-8">Search</h1>
    {isDev ? (
      <div class="rounded-lg border border-yellow-200 bg-yellow-50 dark:border-yellow-800 dark:bg-yellow-950 p-4 text-sm text-yellow-800 dark:text-yellow-200">
        <strong>Search is unavailable in development mode.</strong>
        <p class="mt-1">Run <code class="font-mono">npm run build</code> and <code class="font-mono">npm run preview</code> to use full-text search.</p>
      </div>
    ) : (
      <>
<noscript>
          <p class="text-sm text-gray-600 dark:text-gray-400">
            Full-text search requires JavaScript. Please enable JavaScript in your browser to use this feature.
          </p>
        </noscript>
        <label for="pagefind-search-input" class="block text-sm font-medium mb-2">Search posts</label>
        <div id="search-loading" class="text-sm text-gray-500 py-4">Loading search…</div>
        <div id="search" class="hidden"></div>
        <div
          id="search-status"
          role="status"
          aria-live="polite"
          aria-atomic="true"
          class="sr-only"
        ></div>
      </>
    )}
  </section>
  <script>
    // Load pagefind-ui.js by injecting a <script> tag at runtime.
    // Using import('/pagefind/pagefind-ui.js') fails at build time because Rollup cannot
    // resolve the path (pagefind only generates this file after the Astro build runs).
    // This approach is also required for Astro 6 CSP: is:inline scripts are NOT hashed by
    // Astro's SHA-256 CSP feature, so the init script must be an Astro-processed script
    // (no is:inline). The injected <script src="/pagefind/pagefind-ui.js"> is same-origin
    // and allowed by 'self' in script-src.
    try {
      await new Promise<void>((resolve, reject) => {
        const s = document.createElement('script');
        s.src = '/pagefind/pagefind-ui.js';
        s.onload = () => resolve();
        s.onerror = () => reject(new Error('Failed to load /pagefind/pagefind-ui.js'));
        document.head.appendChild(s);
      });
    } catch (_err) {
      const loadingEl = document.getElementById('search-loading');
      if (loadingEl) loadingEl.textContent = 'Search failed to load. Please try refreshing the page.';
    }

    // @ts-ignore: PagefindUI is set as a global by pagefind-ui.js
    const params = new URLSearchParams(window.location.search);
    const defaultQuery = params.get('q') ?? undefined;
    new window.PagefindUI({ element: '#search', showImages: false, ...(defaultQuery ? { defaultQuery } : {}) });

    // Associate the visible label with the rendered search input
    const input = document.querySelector<HTMLInputElement>('.pagefind-ui__search-input');
    if (input) input.id = 'pagefind-search-input';

    // Hide loading indicator and reveal search widget
    const loading = document.getElementById('search-loading');
    const container = document.getElementById('search');
    if (loading) loading.remove();
    if (container) container.classList.remove('hidden');

    // Announce result count to screen readers
    const status = document.getElementById('search-status');
    if (input && status) {
      input.addEventListener('input', () => {
        setTimeout(() => {
          const results = document.querySelectorAll('.pagefind-ui__result');
          status.textContent = results.length
            ? `${results.length} result${results.length === 1 ? '' : 's'} found`
            : input.value ? 'No results found' : '';
        }, 300);
      });
    }
  </script>
</BaseLayout>

